using ModelContextProtocol.Server;

public class Program
{
    public static readonly DateTime StartedAt = DateTime.UtcNow;

    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddMcpServer(options =>
        {
            options.ServerInfo = new() { Name = "HttpMcpServer", Version = "1.0.0" };
            options.ServerInstructions = "An HTTP MCP server exposing echo tools and configuration resources.";
        })
        .WithHttpTransport()
        .WithToolsFromAssembly()
        .WithResourcesFromAssembly();

        var app = builder.Build();

        app.MapMcp();                          // MCP endpoint at /mcp (Streamable HTTP)
        app.MapGet("/health", () => "ok");     // health check for orchestrators

        app.Run();
    }
}

